export const 鎮宅淫祠 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.4) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    // 符頭：桿＋短桿己鉤＋右圈柱
    線(p => p.M(X(1.0), Z(1.2)).L(X(6.6), Z(1.1)));
    圈(0.7, 1.2);
    圈(6.9, 1.1);
    線(p => p.M(X(1.0), Z(2.7)).L(X(4.6), Z(2.65)).C(X(5.0), Z(2.65), X(5.1), Z(2.9), X(5.0), Z(3.2)));
    圈(0.7, 2.7);
    for (const z of [2.2, 3.5, 4.8])
        圈(7.1, z);
    // 日日箱層
    const 日 = (x0) => {
        線(p => p.M(X(x0), Z(3.6)).L(X(x0), Z(5.9)).L(X(x0 + 2.0), Z(5.85))
            .L(X(x0 + 2.0), Z(3.55)).L(X(x0 - 0.05), Z(3.6)));
        線(p => p.M(X(x0 + 0.1), Z(4.75)).L(X(x0 + 1.9), Z(4.72)), 0.32);
    };
    日(0.9);
    日(3.6);
    // 左密目梯（七箱）
    線(p => p.M(X(0.9), Z(6.6)).L(X(0.9), Z(19.0)));
    線(p => p.M(X(3.3), Z(6.55)).L(X(3.3), Z(18.95)));
    for (let i = 0; i <= 7; i++)
        線(p => p.M(X(0.9), Z(6.6 + i * 1.77)).L(X(3.3), Z(6.55 + i * 1.77)));
    // 右柱：九罒水虫字形疊（摹形從簡）
    // 才/十
    線(p => p.M(X(4.4), Z(7.1)).L(X(6.4), Z(7.05)), 0.36);
    線(p => p.M(X(5.4), Z(6.6)).L(X(5.38), Z(8.6)), 0.36);
    // 九
    出(p => p.M(X(4.9), Z(9.2)).C(X(4.7), Z(10.2), X(4.5), Z(11.0), X(4.3), Z(11.5)), 0.4);
    出(p => p.M(X(4.6), Z(9.7)).L(X(5.9), Z(9.65))
        .L(X(5.95), Z(10.9)).C(X(5.95), Z(11.4), X(6.3), Z(11.55), X(6.7), Z(11.35)), 0.4);
    // 罒
    線(p => p.M(X(4.4), Z(12.2)).L(X(4.4), Z(13.5)).L(X(6.5), Z(13.45))
        .L(X(6.5), Z(12.15)).L(X(4.35), Z(12.2)));
    線(p => p.M(X(5.1), Z(12.25)).L(X(5.08), Z(13.45)), 0.3);
    線(p => p.M(X(5.8), Z(12.2)).L(X(5.78), Z(13.4)), 0.3);
    // 水
    線(p => p.M(X(5.5), Z(14.0)).L(X(5.48), Z(16.3)), 0.36);
    出(p => p.M(X(4.6), Z(14.4)).C(X(4.9), Z(14.9), X(5.2), Z(15.2), X(5.4), Z(15.3)), 0.32);
    出(p => p.M(X(6.4), Z(14.3)).C(X(6.1), Z(14.9), X(5.8), Z(15.3), X(5.6), Z(15.5)), 0.32);
    出(p => p.M(X(5.5), Z(15.6)).C(X(5.1), Z(16.0), X(4.8), Z(16.3), X(4.6), Z(16.5)), 0.32);
    // 虫曲
    出(p => p.M(X(5.0), Z(17.0)).L(X(5.0), Z(18.0)).L(X(6.0), Z(17.95)).L(X(6.0), Z(17.0)), 0.34);
    出(p => p.M(X(5.5), Z(18.0)).C(X(5.5), Z(18.6), X(5.8), Z(18.9), X(6.4), Z(18.85)), 0.34);
};
